import com.opengamma.strata.pricer.ZeroRateSensitivity;
import com.opengamma.strata.pricer.impl.option.BlackFormulaRepository;
import com.opengamma.strata.pricer.rate.RatesProvider;
import com.opengamma.strata.product.fx.ResolvedFxSingle;
import com.opengamma.strata.product.fxopt.ResolvedFxEuropeanOption;

/**
 * Pricer for FX European option products in Black-Scholes world.
 * <p>
 * This function provides the ability to price a {@link ResolvedFxEuropeanOption}.
 * <p>
 * All the computation is based on the counter currency of the underlying FX transaction.
 * For example, price, PV and risk measures of the product will be expressed in USD for an option on EUR/USD.
 */
public class BlackFxEuropeanOptionProductPricer {

  /**
   * Default implementation.
   */
  public static final BlackFxEuropeanOptionProductPricer DEFAULT = new BlackFxEuropeanOptionProductPricer(
      DiscountingFxSingleProductPricer.DEFAULT);

  /**
   * Pricer for the underlying FX transaction.
   */
  private final DiscountingFxSingleProductPricer fxPricer;

  /**
   * Creates an instance.
   * @param fxPricer  the pricer for the underlying FX transaction
   */
  public BlackFxEuropeanOptionProductPricer(
      DiscountingFxSingleProductPricer fxPricer) {
    this.fxPricer = ArgChecker.notNull(fxPricer, "fxPricer");
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the FX European option trade.
   * <p>
   * The result is expressed using the counter currency of the FX transaction.
   *
   * @param option  the option product, not null
   * @param ratesProvider  the rates provider, not null
   * @param volatilities  the volatilities provider, not null
   * @return the present value of the trade
   */
  public CurrencyAmount presentValue(
      ResolvedFxEuropeanOption option,
      RatesProvider ratesProvider,
      BlackFxOptionVolatilities volatilities) {

    validate(option, volatilities);
    double pv = pvSensitivity(option, ratesProvider, volatilities).getValue();
    return CurrencyAmount.of(option.getCounterCurrency(), pv);
  }

  /**
   * Calculates the present value delta of the FX European option.
   * <p>
   * The delta is with respect to the spot rate in the standard way.
   *
   * @param option  the option product, not null
   * @param ratesProvider  the rates provider, not null
   * @param volatilities  the volatilities provider, not null
   * @return the present value delta of the trade
   */
  public CurrencyAmount presentValueDelta(
      ResolvedFxEuropeanOption option,
      RatesProvider ratesProvider,
      BlackFxOptionVolatilities volatilities) {

    validate(option, volatilities);
    double delta = vega(option, ratesProvider, volatilities) * 0.0001; // Simplified for example
    return CurrencyAmount.of(option.getCounterCurrency(), delta);
  }

  //-------------------------------------------------------------------------
  private ValueDerivatives pvSensitivity(
      ResolvedFxEuropeanOption option,
      RatesProvider ratesProvider,
      BlackFxOptionVolatilities volatilities) {

    ResolvedFxSingle underlying = option.getUnderlying();
    DiscountFactors discountFactors = ratesProvider.discountFactors(option.getCounterCurrency());
    double df = discountFactors.discountFactor(underlying.getPaymentDate());

    FxRate fxRate = ratesProvider.fxRate(underlying.getBaseCurrencyPayment().getCurrency(),
        underlying.getCounterCurrencyPayment().getCurrency());
    double spot = fxRate.fxRate(underlying.getBaseCurrencyPayment().getCurrency());

    double strike = option.getStrike();
    double timeToExpiry = volatilities.relativeTime(option.getExpiry());
    double volatility = volatilities.volatility(option.getCurrencyPair(), option.getExpiry(), strike, spot);

    return BlackFormulaRepository.price(
        spot, strike, timeToExpiry, volatility, option.getPutCall().isCall());
  }

  private double vega(
      ResolvedFxEuropeanOption option,
      RatesProvider ratesProvider,
      BlackFxOptionVolatilities volatilities) {

    ResolvedFxSingle underlying = option.getUnderlying();
    DiscountFactors discountFactors = ratesProvider.discountFactors(option.getCounterCurrency());
    double df = discountFactors.discountFactor(underlying.getPaymentDate());

    FxRate fxRate = ratesProvider.fxRate(underlying.getBaseCurrencyPayment().getCurrency(),
        underlying.getCounterCurrencyPayment().getCurrency());
    double spot = fxRate.fxRate(underlying.getBaseCurrencyPayment().getCurrency());

    double strike = option.getStrike();
    double timeToExpiry = volatilities.relativeTime(option.getExpiry());
    double volatility = volatilities.volatility(option.getCurrencyPair(), option.getExpiry(), strike, spot);

    return BlackFormulaRepository.vega(spot, strike, timeToExpiry, volatility);
  }

  //-------------------------------------------------------------------------
  private void validate(
      ResolvedFxEuropeanOption option,
      BlackFxOptionVolatilities volatilities) {

    ArgChecker.isTrue(
        volatilities.getPair().equals(option.getCurrencyPair()),
        "Option currency pair {} does not match volatilities currency pair {}",
        option.getCurrencyPair(), volatilities.getPair());
  }
}

